class Solution {
    public String reversePrefix(String word, char ch) {
        int index = word.indexOf(ch);
        if (index != -1) {
            return word.substring(0, index + 1).reverse() + word.substring(index + 1);
        } else {
            return word;
        }
    }
}
```

